Greedy insertion with cheapest incremental cost across all feasible positions and fallback to empty assign slot.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := 0; jj < len(oris); jj++ {
		bestAssignIdx := -1
		bestCostDelta := 1e100
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		fallbackIdx := -1
		if dispatch.AssignsLen < MAXASSIGNS {
			fallbackIdx = dispatch.AssignsLen
		}

		for aa := 0; aa <= dispatch.AssignsLen && aa < MAXASSIGNS; aa++ {
			assign := &dispatch.Assigns[aa]

			oldState := assign.StationCurrent
			oldCost := assign.Cost

			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - oldCost

				if costDelta < bestCostDelta && newCost >= 0 {
					bestCostDelta = costDelta
					bestAssignIdx = aa
				}

				assign.RemoveShip(shipID)
				assign.GenRoute()
				if aa == dispatch.AssignsLen && assign.StationsLen == 0 {
					assign.StationCurrent = oldState
				}
			}
		}

		if bestAssignIdx >= 0 {
			target := &dispatch.Assigns[bestAssignIdx]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
		} else {
			if fallbackIdx >= 0 {
				target := &dispatch.Assigns[fallbackIdx]
				ok := target.AddShip(shipID, ori, des)
				if ok {
					target.GenRoute()
					if fallbackIdx == dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

